('computer-science:1-2-4-data-storage-numbers:exam:78d20ead', 'computer-science', 'computer-science:1-2-4-data-storage-numbers', '1.2.4 Data Storage: Numbers', 'exam', 'mcq', 1, '{"num": "N13", "question": "<p>Which of these is the main reason hexadecimal is used when writing down binary values by hand?</p>", "options": ["It gives a much shorter way to write the same value, cutting down transcription errors", "It allows a computer''s processor to calculate noticeably faster than working in pure binary", "It is the number system that a computer''s memory actually stores every value in", "It removes the need for a computer to ever convert a value back into binary"], "hint": "Think about who hexadecimal shorthand is actually FOR — the hardware, or the person reading and writing the value."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li>It gives a much shorter way to write the same value, cutting down transcription errors</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Only the correct option scores. The other three options wrongly suggest hex changes how the hardware itself works — it is purely a human-facing shorthand for binary.</li>\n</ul>\n</div>", "modelAnswer": "It gives a much shorter way to write the same value, cutting down transcription errors."}'::jsonb),
('computer-science:1-2-4-data-storage-numbers:exam:c826642c', 'computer-science', 'computer-science:1-2-4-data-storage-numbers', '1.2.4 Data Storage: Numbers', 'exam', 'mcq', 1, '{"num": "N14", "question": "<p>Which of these is NOT a valid hexadecimal digit?</p>", "options": ["G", "9", "C", "2"], "hint": "Hexadecimal only ever uses 16 digits in total: 0-9, then the letters A through F."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li>G</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Only the correct option scores. Hexadecimal digits run from 0-9 and then A-F only; G is not a valid hexadecimal digit.</li>\n</ul>\n</div>", "modelAnswer": "G — hexadecimal digits only go up to F (representing 15)."}'::jsonb),
