('computer-science:1-2-4-data-storage-numbers:mcq:364636b7', 'computer-science', 'computer-science:1-2-4-data-storage-numbers', '1.2.4 Data Storage: Numbers', 'mcq', 'mcq', 1, '{"question": "Which term describes the LEFT-most bit of an 8-bit binary number, the one carrying the largest place value?", "options": ["Most significant bit (MSB)", "Least significant bit (LSB)", "Overflow bit", "Carry bit"]}'::jsonb, '{"answer": 0, "explain": "The left-most bit carries the biggest place value (128) and is called the most significant bit; the right-most bit (value 1) is the least significant bit."}'::jsonb),
('computer-science:1-2-4-data-storage-numbers:mcq:58635219', 'computer-science', 'computer-science:1-2-4-data-storage-numbers', '1.2.4 Data Storage: Numbers', 'mcq', 'mcq', 1, '{"question": "What is hexadecimal 3C in denary?", "options": ["60", "48", "54", "63"]}'::jsonb, '{"answer": 0, "explain": "(3 × 16) + 12 = 48 + 12 = 60."}'::jsonb),
('computer-science:1-2-4-data-storage-numbers:mcq:4095a014', 'computer-science', 'computer-science:1-2-4-data-storage-numbers', '1.2.4 Data Storage: Numbers', 'mcq', 'mcq', 1, '{"question": "What is denary 58 written as a 2-digit hexadecimal number?", "options": ["3A", "2E", "4A", "3F"]}'::jsonb, '{"answer": 0, "explain": "58 ÷ 16 = 3 remainder 10. 3 stays as 3, and 10 becomes A, giving 3A."}'::jsonb),
